<?php
 namespace WPAICG\Chat\Frontend\Shortcode\ConfiguratorMethods; use WPAICG\Chat\Storage\BotSettingsManager; if (!defined('ABSPATH')) { exit; } function get_tts_settings_logic(array $settings): array { if (!class_exists(BotSettingsManager::class)) { return [ 'tts_provider' => 'Google', 'tts_voice_id' => '', 'tts_auto_play' => false, 'tts_openai_model_id' => 'tts-1', 'tts_elevenlabs_model_id' => '', ]; } $tts_provider = $settings['tts_provider'] ?? BotSettingsManager::DEFAULT_TTS_PROVIDER; $tts_voice_id = $settings['tts_voice_id'] ?? ''; $tts_auto_play = ($settings['tts_auto_play'] ?? BotSettingsManager::DEFAULT_TTS_AUTO_PLAY) === '1'; $tts_openai_model_id = $settings['tts_openai_model_id'] ?? BotSettingsManager::DEFAULT_TTS_OPENAI_MODEL_ID; $tts_elevenlabs_model_id = $settings['tts_elevenlabs_model_id'] ?? BotSettingsManager::DEFAULT_TTS_ELEVENLABS_MODEL_ID; return [ 'tts_provider' => $tts_provider, 'tts_voice_id' => $tts_voice_id, 'tts_auto_play' => $tts_auto_play, 'tts_openai_model_id' => $tts_openai_model_id, 'tts_elevenlabs_model_id' => $tts_elevenlabs_model_id, ]; }